import * as path from 'path';
import * as Module from 'module';
import findRoot = require('find-root');

/**
 * Class for resolve root and asset paths.
 * @class PathUtils
 * @memberof jibo.utils
 */
class PathUtils {

    /**
     * The token separating asset packs.
     * @name jibo.utils.PathUtils.ASSET_TOKEN
     * @type {String}
     * @private
     * @readOnly
     */
    private static ASSET_TOKEN:string = '://';

    /**
     * Traverses up the directories until the first folder with a `package.json` file.
     * This also works for requests with asset-pack, e.g., "core://resources/fonts.css".
     * @method jibo.utils.PathUtils.findRoot
     * @param {String} [start] The starting directory, empty uses current working directory.
     * @return {String} The root directory which contains `package.json`.
     */
    static findRoot(start?:string): string {
        if (start) {
            let assetPack:string = PathUtils.getAssetPack(start);
            if (assetPack) {
                return PathUtils.resolveAssetPack(assetPack);
            }
        }
        return findRoot(start || process.cwd());
    }

    /**
     * Get a project name. Useful for figuring out the asset pack.
     * @method jibo.utils.PathUtils.getProjectName
     * @param {String} dir The directory. Should contain `package.json`.
     * @return {String} The name in the `package.json`.
     */
    static getProjectName(dir:string): string {
        return require(path.join(dir, 'package.json')).name;
    }

    /**
     * Basic check to see if a URI is a URL.
     * @method jibo.utils.PathUtils.isURL
     * @param {String} uri String path to test.
     * @return {Boolean} `true` if URI is a URL.
     */
    static isURL(uri:string): boolean {
        return uri.startsWith('https://') || uri.startsWith('http://') || uri.startsWith('file://');
    }

    /**
     * Basic check to see if a URI is an image.
     * @method jibo.utils.PathUtils.isImage
     * @param {String} uri String path to test.
     * @return {Boolean} `true` if URI contains an image extension.
     */
    static isImage(uri:string): boolean {
        return uri && /^\.(jpg|png|gif|jpeg)$/i.test(path.extname(uri));
    }

    /**
     * Set the default path for behaviors, rules, animations, etc.
     * @method jibo.utils.PathUtils.setDefaultPath
     * @param {String} parentDir The parent directory.
     * @param {String} fileName The file name.
     * @return {String} asset URI to load.
     */
    static setDefaultPath(parentDir:string, fileName:string):string {
        let split = fileName.split(PathUtils.ASSET_TOKEN);
        if (split.length === 2) {
            return split[0] + PathUtils.ASSET_TOKEN + path.join(parentDir, split[1]);
        } else {
            return path.join(parentDir, fileName);
        }
    }

    /**
     * Get the asset pack from the file request, if available.
     * @method jibo.utils.PathUtils.getAssetPack
     * @param {String} fileName The file name.
     * @return {String} The asset pack name, otherwise returns ''.
     */
    static getAssetPack(fileName:string):string {
        const split = fileName.split(PathUtils.ASSET_TOKEN);
        return (split.length === 1) ? "" : split[0];
    }

    /**
     * Get the asset pack from the asset file, if available.
     * @method jibo.utils.PathUtils.resolveAssetPack
     * @param {String} assetPack The assetPack name name.
     * @return {String} Full path to the root directory.
     */
    static resolveAssetPack(assetPack:string):string {
        // if the asset pack has the asset token, strip it off for comparison/resolution
        if (assetPack && assetPack.endsWith(PathUtils.ASSET_TOKEN)) {
            assetPack = assetPack.substr(0, assetPack.length - PathUtils.ASSET_TOKEN.length);
        }
        // "core" reserved assetPack name means jibo's module
        if (assetPack === 'core' || assetPack === 'jibo') {
            assetPack = 'jibo';
            let packagePath:string = PathUtils.resolve(assetPack + "/package.json");
            // if we're not running in a skill or the jibo module unit tests
            // then the core module is the procces current working directory
            if(!packagePath) {
                // if we're in atom do something different because process.cwd()
                // is different in atom
                let uri:string = process.cwd();
                if((global as any).atom) {
                    uri = atom.workspace.getActivePaneItem().uri;
                }
                packagePath = findRoot(uri);
                return packagePath;
            }
            return path.dirname(packagePath);
        }
        const packagePath:string = PathUtils.resolve(assetPack + "/package.json");
        return path.dirname(packagePath);

    }

    /**
     * Get an asset pack URI.
     * @method jibo.utils.PathUtils.getAssetUri
     * @param {String} fileName The file name to load, can be `asset-pack://etc`.
     * @param {String} assetPack The current asset pack to load within.
     * @param {string} [resourceRoot] The root of the skill to get the asset from (defaults to current skill).
     * @return {String} The result URI.
     */
    static getAssetUri(fileName:string, assetPack:string = '', resourceRoot?:string):string {

        let split:string[] = fileName.split(PathUtils.ASSET_TOKEN);

        // handle asset packs like project://path/to/file.txt
        if (split.length === 2) {
            assetPack = split[0];
            fileName = split[1];
        }

        // Get asset pack
        if (assetPack) {
            resourceRoot = PathUtils.resolveAssetPack(assetPack);
        } else if (path.isAbsolute(fileName)) {
            return fileName;
        } else if (!resourceRoot) {
            resourceRoot = PathUtils.findRoot();
        }
        return path.join(resourceRoot, fileName);
    }

    /**
     * Get asset source from filename and asset pack.
     * @method jibo.utils.PathUtils.getAudioUri
     * @param {String} fileName The file name to load, can be `asset-pack://etc`.
     * @param {String} currentAssetPack The current asset pack to load within.
     * @param {String} [resourceRoot] The root to the skill.
     * @return {String} The result URI.
     */
    static getAudioUri(fileName:string, currentAssetPack:string = '', resourceRoot?:string):string {
        let audioPath = PathUtils.setDefaultPath('audio', fileName);
        return PathUtils.getAssetUri(audioPath, currentAssetPack, resourceRoot); // callback deprecated
    }

    /**
     * Get asset source from filename and asset pack.
     * @method jibo.utils.PathUtils.getTimelineUri
     * @param {String} fileName The file name to load, can be `asset-pack://etc`.
     * @param {String} currentAssetPack The current asset pack to load within.
     * @param {String} [resourceRoot] The root to the skill.
     * @return {String} The result URI.
     */
    static getTimelineUri(fileName:string, currentAssetPack:string = '', resourceRoot?:string):string {
        let timelinePath = PathUtils.setDefaultPath('timelines', fileName);
        return PathUtils.getAssetUri(timelinePath, currentAssetPack, resourceRoot); // callback deprecated
    }

    /**
     * Modified from [https://github.com/sindresorhus/resolve-from](https://github.com/sindresorhus/resolve-from). Return the path to the
     * module's `package.json`, not the module directory.
     * @method jibo.utils.PathUtils.resolve
     * @param {String} moduleId The module to resolve path to.
     * @param {String} [fromPath=process.cwd()] Resolve path from
     * @return {String} The resolved file path.
     */
    static resolve(moduleId:string, fromPath?:string):string {
        let fromDir:string = path.resolve(fromPath || process.cwd());
        let fromFile:string = path.join(fromDir, 'noop.js');
        try {
            return Module._resolveFilename(moduleId, {
                id: fromFile,
                filename: fromFile,
                paths: Module._nodeModulePaths(fromDir)
            });
        } catch (err) {
            return null;
        }
    }
}

export default PathUtils;
